function isAuthorized(request, env) {
  const apiKey = env.API_KEY;
  if (!apiKey) return false;

  const authHeader = request.headers.get("Authorization") || "";
  const xApiKey = request.headers.get("x-api-key") || "";
  const bearer = authHeader.toLowerCase().startsWith("bearer ") ? authHeader.slice(7).trim() : "";

  return timingSafeEqual(bearer, apiKey) || timingSafeEqual(xApiKey, apiKey);
}

function timingSafeEqual(a, b) {
  if (typeof a !== "string" || typeof b !== "string") return false;
  if (a.length !== b.length) return false;
  let out = 0;
  for (let i = 0; i < a.length; i++) out |= a.charCodeAt(i) ^ b.charCodeAt(i);
  return out === 0;
}

async function readJson(request) {
  const contentType = request.headers.get("content-type") || "";
  if (!contentType.toLowerCase().includes("application/json")) {
    throw new Error("Content-Type must be application/json");
  }
  return await request.json();
}

function validateEmailPayload(body) {
  if (!body || typeof body !== "object") throw new Error("Invalid request body");
  if (!body.to || !isValidEmail(body.to)) throw new Error("Invalid or missing 'to'");
  if (!body.subject || typeof body.subject !== "string") throw new Error("Invalid or missing 'subject'");
  if (!body.text && !body.html) throw new Error("Either 'text' or 'html' is required");
}

function validatePaymentPayload(body) {
  if (!body || typeof body !== "object") throw new Error("Invalid request body");
  if (!Number.isInteger(body.amount) || body.amount <= 0) throw new Error("Invalid or missing 'amount'");
  if (!body.currency || typeof body.currency !== "string") throw new Error("Invalid or missing 'currency'");
  if (body.amount > 1000000) throw new Error("Amount exceeds limit");
}

function isValidEmail(email) {
  return typeof email === "string" && /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
}

async function sendEmailWithSendGrid(body, env) {
  const apiKey = env.SENDGRID_API_KEY;
  const fromEmail = env.SENDGRID_FROM_EMAIL;

  if (!apiKey) throw new Error("Missing SENDGRID_API_KEY");
  if (!fromEmail) throw new Error("Missing SENDGRID_FROM_EMAIL");

  const payload = {
    personalizations: [
      {
        to: [{ email: body.to }],
        ...(body.cc ? { cc: Array.isArray(body.cc) ? body.cc.map((email) => ({ email })) : [{ email: body.cc }] } : {}),
        ...(body.bcc ? { bcc: Array.isArray(body.bcc) ? body.bcc.map((email) => ({ email })) : [{ email: body.bcc }] } : {}),
        ...(body.dynamicTemplateData ? { dynamic_template_data: body.dynamicTemplateData } : {}),
      },
    ],
    from: { email: fromEmail, ...(body.fromName ? { name: body.fromName } : {}) },
    subject: body.subject,
    content: [
      ...(body.text ? [{ type: "text/plain", value: body.text }] : []),
      ...(body.html ? [{ type: "text/html", value: body.html }] : []),
    ],
    ...(body.replyTo ? { reply_to: { email: body.replyTo } } : {}),
    ...(body.customArgs ? { custom_args: body.customArgs } : {}),
  };

  const res = await fetch("https://api.sendgrid.com/v3/mail/send", {
    method: "POST",
    headers: {
      Authorization: `Bearer ${apiKey}`,
      "Content-Type": "application/json",
    },
    body: JSON.stringify(payload),
  });

  if (!res.ok) {
    const detail = await safeText(res);
    throw new Error(`SendGrid error: ${res.status} ${detail}`);
  }

  return { status: res.status, message: "Accepted" };
}

async function createPaymentIntentWithStripe(body, env) {
  const apiKey = env.STRIPE_SECRET_KEY;
  if (!apiKey) throw new Error("Missing STRIPE_SECRET_KEY");

  const params = new URLSearchParams();
  params.set("amount", String(body.amount));
  params.set("currency", String(body.currency).toLowerCase());
  if (body.customer) params.set("customer", body.customer);
  if (body.description) params.set("description", body.description);
  if (body.metadata && typeof body.metadata === "object") {
    for (const [k, v] of Object.entries(body.metadata)) {
      if (v !== undefined && v !== null) params.set(`metadata[${k}]`, String(v));
    }
  }
  if (body.receipt_email && isValidEmail(body.receipt_email)) params.set("receipt_email", body.receipt_email);
  if (body.automatic_payment_methods) params.set("automatic_payment_methods[enabled]", body.automatic_payment_methods ? "true" : "false");

  const res = await fetch("https://api.stripe.com/v1/payment_intents", {
    method: "POST",
    headers: {
      Authorization: `Bearer ${apiKey}`,
      "Content-Type": "application/x-www-form-urlencoded",
    },
    body: params.toString(),
  });

  const data = await res.json().catch(() => null);
  if (!res.ok) {
    const message = data?.error?.message || "Stripe request failed";
    throw new Error(`Stripe error: ${res.status} ${message}`);
  }

  return {
    id: data.id,
    client_secret: data.client_secret,
    status: data.status,
    amount: data.amount,
    currency: data.currency,
  };
}

async function safeText(res) {
  try {
    return await res.text();
  } catch {
    return "";
  }
}

function json(obj, status = 200) {
  return new Response(JSON.stringify(obj), {
    status,
    headers: {
      "content-type": "application/json; charset=utf-8",
      "cache-control": "no-store",
    },
  });
}

function corsResponse(response, status, env) {
  const headers = new Headers(response ? response.headers : undefined);
  headers.set("Access-Control-Allow-Origin", env?.CORS_ORIGIN || "*");
  headers.set("Access-Control-Allow-Methods", "GET,POST,OPTIONS");
  headers.set("Access-Control-Allow-Headers", "Content-Type, Authorization, X-API-Key");
  headers.set("Access-Control-Max-Age", "86400");
  headers.set("Vary", "Origin");

  if (!response) {
    return new Response(null, { status, headers });
  }

  return new Response(response.body, {
    status: response.status || status,
    headers,
  });
}